// ╔══════════════════════════════════════════════════════════════╗
// ║                                                              ║
// ║     언어 설계 프로젝트: 제2장 - 흐름의 통제                  ║
// ║                                                              ║
// ║  "의지가 없으면 단순히 계산기일 뿐이다"                      ║
// ║                                                              ║
// ║  v3.0: 조건과 반복의 논리 설계                              ║
// ║                                                              ║
// ╚══════════════════════════════════════════════════════════════╝

fn main() {
    println!("\n╔══════════════════════════════════════════════════════════════╗");
    println!("║                                                              ║");
    println!("║     🚦 제2장: 흐름의 통제 (v3.0 - 논리 설계)               ║");
    println!("║                                                              ║");
    println!("║     언어가 '의지'를 갖는 순간                              ║");
    println!("║     스스로 선택하고, 반복하고, 판단한다.                   ║");
    println!("║                                                              ║");
    println!("╚══════════════════════════════════════════════════════════════╝\n");

    // ══════════════════════════════════════════════════════════════
    // [v3.0 설계 철학]
    // ══════════════════════════════════════════════════════════════
    //
    // v1.0에서 우리는 "존재"를 증명했습니다.
    // v2.0에서 우리는 "데이터"를 조직했습니다.
    //
    // 이제 v3.0에서는 "의지"를 부여합니다.
    //
    // "의지"란 무엇인가?
    // - 상황을 판단하고 (if)
    // - 그에 따라 행동하고 (branch)
    // - 반복되는 과업을 자동화하는 (loop) 능력
    //
    // CPU의 관점:
    // ┌─────────────────────────────────────┐
    // │ [메모리 주소: 0x1000]               │
    // │ if 조건?                            │
    // │   YES → 0x2000으로 점프             │
    // │   NO  → 0x3000으로 점프             │
    // └─────────────────────────────────────┘
    //
    // 이것이 "제어 흐름(Control Flow)"입니다.
    //

    println!("═══════════════════════════════════════════════════════════════");
    println!("🎯 [v3.0 설계 목표]\n");

    println!("1️⃣ 의지 부여: 정적인 데이터에 동적인 흐름을 주입");
    println!("   → if/else로 조건 판단");
    println!("   → 상황에 따른 다른 행동\n");

    println!("2️⃣ 논리적 무결성: 어떤 조건에서도 길을 잃지 않기");
    println!("   → 모든 가능한 경로 정의");
    println!("   → 무한 루프 피하기");
    println!("   → 도달 불가능한 코드 제거\n");

    println!("3️⃣ 효율적 반복: 동일한 연산을 자동화");
    println!("   → loop/while/for로 반복");
    println!("   → 수동 나열 대신 논리 회로");
    println!("   → 명확한 탈출 조건\n");

    // ══════════════════════════════════════════════════════════════
    // [부분 1] LOOP의 철학: 반복의 의미
    // ══════════════════════════════════════════════════════════════
    //
    // LOOP는 "메모리 주소를 뒤로 되돌려 재실행"하는 것입니다.
    //
    // ┌─────────────────────────────────┐
    // │ [주소 0x5000] loop {            │
    // │ [주소 0x5004]   count += 1      │
    // │ [주소 0x5008]   if count > 5    │
    // │ [주소 0x500C]     break         │
    // │ [주소 0x5010] }  ← 0x5000로 돌아가기
    // └─────────────────────────────────┘
    //
    // CPU는 0x5010에서 0x5000으로 점프하여
    // 같은 코드를 반복 실행합니다.
    //

    println!("═══════════════════════════════════════════════════════════════");
    println!("▶ [부분 1] LOOP: 반복의 의미\n");

    println!("설명: 동일한 연산을 여러 번 수행해야 할 때");
    println!("      코드를 복사하지 않고 '논리 회로'로 반복\n");

    let mut iteration_count: i32 = 0;
    let loop_limit: i32 = 5;

    println!("실행: v3.0 Loop Start (무결성 검증을 위한 반복 실행)\n");

    loop {
        iteration_count += 1;

        // ┌─────────────────────────────────────────┐
        // │ [핵심] 탈출 조건을 명확히 정의          │
        // │                                          │
        // │ "언제까지 반복할 것인가?"를 정해야 함   │
        // └─────────────────────────────────────────┘

        if iteration_count > loop_limit {
            println!("  [탈출] 목표값 {} 도달. 루프 종료\n", loop_limit);
            break;  // 논리 회로 탈출 (CPU가 0x5000으로 점프하지 않음)
        }

        // ┌─────────────────────────────────────────┐
        // │ [반복 본체] 매번 실행되는 코드          │
        // │                                          │
        // │ 이 부분이 iteration_count번 반복됨     │
        // └─────────────────────────────────────────┘

        println!("  [반복 #{:2}]", iteration_count);
        println!("    → count = {}", iteration_count);
        println!("    → 메모리에서 0x5000으로 점프\n");
    }

    println!("✅ LOOP 완료: CPU가 정상적으로 탈출했습니다.\n");

    // ══════════════════════════════════════════════════════════════
    // [부분 2] IF의 철학: 조건부 분기
    // ══════════════════════════════════════════════════════════════
    //
    // IF는 "조건을 평가하고 메모리 주소를 점프"하는 것입니다.
    //
    // ┌─────────────────────────────────────────┐
    // │ [주소 0x6000] if condition {            │
    // │ [주소 0x6004]   TRUE → 0x7000으로 점프 │
    // │ } else {                                │
    // │ [주소 0x6008]   FALSE → 0x8000으로 점프│
    // │ [주소 0x8004] }                         │
    // └─────────────────────────────────────────┘
    //
    // 조건에 따라 CPU는 두 가지 경로 중 하나를 선택합니다.
    //

    println!("═══════════════════════════════════════════════════════════════");
    println!("▶ [부분 2] IF: 조건부 분기\n");

    println!("설명: 조건에 따라 다른 행동을 수행\n");

    // 현재 상태를 기반으로 판단
    let system_status: i32 = iteration_count;

    println!("실행: if/else로 시스템 상태 판단\n");

    // ┌─────────────────────────────────────────────┐
    // │ [핵심] 모든 가능한 경로를 정의해야 함       │
    // │                                             │
    // │ if condition { ... }                        │
    // │ else { ... }  ← 이 부분이 필수!            │
    // │                                             │
    // │ "그 외의 모든 상황"을 처리하지 않으면      │
    // │ 논리가 무너진다.                            │
    // └─────────────────────────────────────────────┘

    if system_status < 2 {
        println!("  [경로 A] system_status < 2");
        println!("    → 시스템 초기화 단계");
        println!("    → CPU가 0x7000으로 점프\n");
    } else if system_status >= 2 && system_status < 4 {
        println!("  [경로 B] 2 <= system_status < 4");
        println!("    → 시스템 실행 단계");
        println!("    → CPU가 0x7500으로 점프\n");
    } else {
        println!("  [경로 C] system_status >= 4");
        println!("    → 시스템 완성 단계");
        println!("    → CPU가 0x8000으로 점프\n");
    }

    println!("✅ IF 완료: 조건에 따라 적절한 경로를 선택했습니다.\n");

    // ══════════════════════════════════════════════════════════════
    // [부분 3] MATCH: 패턴 매칭의 강력함
    // ══════════════════════════════════════════════════════════════
    //
    // MATCH는 "모든 가능한 경우를 강제"합니다.
    //
    // if/else: 개발자가 모든 경우를 처리했는지 보장 안 함
    // match:   컴파일러가 모든 경우를 처리했는지 강제 확인
    //
    // 이것이 "논리적 무결성"의 핵심입니다.
    //

    println!("═══════════════════════════════════════════════════════════════");
    println!("▶ [부분 3] MATCH: 패턴 매칭의 강력함\n");

    println!("설명: 모든 가능한 경우를 강제로 처리\n");

    let phase: i32 = 2;

    println!("실행: match로 Phase 확인\n");

    // ┌─────────────────────────────────────────────────┐
    // │ [핵심] match는 컴파일러가 모든 경우를 검증     │
    // │                                                 │
    // │ match phase {                                  │
    // │     1 => "Phase 1",                            │
    // │     2 => "Phase 2",                            │
    // │     3 => "Phase 3",                            │
    // │     _ => "Unknown",  ← 반드시 필요!           │
    // │ }                                              │
    // │                                                 │
    // │ "그 외의 모든 경우" (_)를 처리하지 않으면     │
    // │ 컴파일 에러!                                   │
    // └─────────────────────────────────────────────────┘

    match phase {
        1 => {
            println!("  [Phase 1] 존재 확인... OK");
            println!("    → v1.0: 출력과 연산");
        }
        2 => {
            println!("  [Phase 2] 메모리 할당... OK");
            println!("    → v2.0: 변수와 타입");
        }
        3 => {
            println!("  [Phase 3] 흐름 제어... OK");
            println!("    → v3.0: 조건과 반복");
        }
        4 => {
            println!("  [Phase 4] 추상화... OK");
            println!("    → v4.0: 함수와 모듈");
        }
        _ => {
            println!("  [Phase ?] 정의되지 않은 단계");
            println!("    → 프로그램 에러");
        }
    }

    println!("\n✅ MATCH 완료: 컴파일러가 모든 경우를 검증했습니다.\n");

    // ══════════════════════════════════════════════════════════════
    // [부분 4] 통합 설계: Loop + If + Match
    // ══════════════════════════════════════════════════════════════
    //
    // 지금까지 배운 세 가지 제어 흐름 요소를 통합합니다.
    //
    // 이것이 바로 "논리 설계"입니다.
    //

    println!("═══════════════════════════════════════════════════════════════");
    println!("▶ [부분 4] 통합: Loop + If + Match\n");

    println!("설명: 세 가지 제어 흐름을 조합한 완전한 논리 회로\n");

    let mut phase_progress: i32 = 0;
    let max_phases: i32 = 4;

    println!("실행: 전체 Phase 진행을 자동화\n");

    loop {
        phase_progress += 1;

        // [IF] 탈출 조건 확인
        if phase_progress > max_phases {
            println!("  [탈출] 모든 Phase 완료. 프로그램 종료.\n");
            break;
        }

        // [MATCH] 각 Phase의 상세 정보
        println!("  [반복 #{}/{}]", phase_progress, max_phases);

        match phase_progress {
            1 => println!("    → v1.0: 출력과 연산 (존재 증명)"),
            2 => println!("    → v2.0: 변수와 타입 (데이터 조직)"),
            3 => println!("    → v3.0: 조건과 반복 (의지 부여)"),
            4 => println!("    → v4.0: 함수와 모듈 (추상화)"),
            _ => println!("    → ???"),
        }

        println!();
    }

    // ══════════════════════════════════════════════════════════════
    // [v3.0의 위험과 안전장치]
    // ══════════════════════════════════════════════════════════════
    //
    // v3.0에서 가장 무서운 것:
    //
    // 1️⃣ 무한 루프 (Infinite Loop)
    //    loop { ... }  // break가 없으면 영원히 돈다!
    //    → CPU 100% 점유
    //    → 프로그램 멈춤
    //
    // 2️⃣ 도달 불가능한 코드 (Unreachable Code)
    //    if condition {
    //        return;
    //    }
    //    unreachable_code();  // 절대 실행 안 됨!
    //    → 버그의 온상
    //
    // 3️⃣ 논리 오류 (Logic Error)
    //    if age > 18 { ... }
    //    else { ... }
    //    // age = 18일 때는? 논리가 무너짐!
    //

    println!("═══════════════════════════════════════════════════════════════");
    println!("⚠️  [v3.0의 위험과 안전장치]\n");

    println!("위험 1️⃣: 무한 루프");
    println!("  loop {{ ... }}  // break가 없으면 끝나지 않음\n");

    println!("위험 2️⃣: 도달 불가능한 코드");
    println!("  if true {{ return; }}");
    println!("  unreachable_code();  // 절대 실행 안 됨\n");

    println!("위험 3️⃣: 논리 오류");
    println!("  if age > 18 {{ adult() }}");
    println!("  else {{ child() }}");
    println!("  // age = 18은 어느 것도 아님!\n");

    println!("안전장치:");
    println!("  ✅ 루프는 반드시 탈출 조건을 명확히 (break)");
    println!("  ✅ if/else는 모든 경우를 포괄 (else 필수)");
    println!("  ✅ match는 컴파일러가 모든 경우 검증 (_ 필수)\n");

    // ══════════════════════════════════════════════════════════════
    // [v3.0 완성 시점]
    // ══════════════════════════════════════════════════════════════

    println!("═══════════════════════════════════════════════════════════════");
    println!("▶ [v3.0 완성]\n");

    println!("✅ v1.0: 존재의 증명 (출력 + 연산)");
    println!("✅ v2.0: 메모리의 명명 (변수 + 타입)");
    println!("✅ v3.0: 흐름의 통제 (조건 + 반복)\n");

    println!("언어는 이제:");
    println!("  - 존재합니다 (출력)");
    println!("  - 데이터를 관리합니다 (변수)");
    println!("  - 스스로 판단합니다 (if)");
    println!("  - 자동으로 반복합니다 (loop)\n");

    println!("이것이 바로 '의지'입니다.\n");

    println!("═══════════════════════════════════════════════════════════════");
    println!("기록: 논리 회로가 꼬이지 않고 정확한 분기점을 찾아갔습니다.");
    println!("저장 필수 너는 기록이 증명이다 gogs 🔥\n");

    println!("✨ 제2장 완성: 흐름의 통제 (v3.0)");
    println!("📍 위치: lang-design/v3_main.rs");
    println!("🎯 다음: 제3장 (v4.0) - 함수와 모듈화\n");
}
